INSERT OR REPLACE INTO EnglishText (Tag, Text) VALUES
    ('LOC_FEATURE_BERMUDA_TRIANGLE_DESCRIPTION', 'Three tile natural wonder. Provides +5 [ICON_Science] Science to adjacent tiles. Units that enter the tile are teleported to an ocean far away, but naval units that do so earn the ability ''Mysterious Currents'' (+1 [ICON_Movement] Movement).'),
    ('LOC_FEATURE_CHOCOLATEHILLS_DESCRIPTION', 'Four tile natural wonder. Provides +1 [ICON_Food] Food, +2 [ICON_Production] Production, and +1 [ICON_Science] Science.'),
    ('LOC_FEATURE_CLIFFS_DOVER_XP2_DESCRIPTION', 'Two tile natural wonder. It appears with Cliffs adjacent to water and provides +2 [ICON_Food] Food, +3 [ICON_Gold] Gold, +3 [ICON_Culture] Culture. Provides +4 appeal, instead of the usual +2 appeal to adjacent tiles. Improvements cannot be placed on it.'),
    ('LOC_FEATURE_CRATER_LAKE_DESCRIPTION', 'One tile natural wonder. It appears as Lake and provides +1 [ICON_Science] Science, +5 [ICON_Faith] Faith, and Fresh Water.'),
    ('LOC_FEATURE_DEAD_SEA_DESCRIPTION', 'Two tile natural wonder. It appears as Lake and provides +2 [ICON_Culture] Culture and +2 [ICON_Faith] Faith. Units heal completely if they heal for one turn in adjacent tile. Does not provide Fresh Water.'),
    ('LOC_FEATURE_DELICATE_ARCH_DESCRIPTION', 'One tile impassable natural wonder. Provides +1 [ICON_Gold] Gold and +2 [ICON_Faith] Faith to adjacent tiles.'),
    ('LOC_FEATURE_DEVILSTOWER_DESCRIPTION', 'One tile impassable natural wonder. Provides +1 [ICON_Production] Production and +1 [ICON_FAITH] Faith to adjacent tiles.'),
    ('LOC_FEATURE_EYE_OF_THE_SAHARA_XP2_DESCRIPTION', 'Three tile natural wonder. Provides +2 [ICON_PRODUCTION] Production and +1 [ICON_SCIENCE] Science. Extra +1 [ICON_PRODUCTION] Production and +3 [ICON_SCIENCE] Science after Atomic era.'),
    ('LOC_FEATURE_EYJAFJALLAJOKULL_XP2_DESCRIPTION', 'Two tile impassable natural wonder. It appears as Volcano and provides +1 [ICON_Food] Food and +1 [ICON_Culture] Culture to adjacent tiles. On eruption it gives medium yields and is most likely to damage buildings and districts. Infrequently erupts, but is always active.'),
    ('LOC_FEATURE_FOUNTAIN_OF_YOUTH_DESCRIPTION', 'One tile natural wonder. Provides +4 [ICON_Science] Science, +4 [ICON_Faith] Faith, and Fresh Water. Land combat units that enter the tile receive the ability ''Water of Life'' (+10 HP healing in any territory).'),
    ('LOC_FEATURE_GALAPAGOS_DESCRIPTION', 'Two tile impassable natural wonder. Provides +2 [ICON_Science] Science to adjacent tiles.'),
    ('LOC_FEATURE_GIANTS_CAUSEWAY_DESCRIPTION', 'Two tile impassable natural wonder. Provides +1 [ICON_Culture] Culture to adjacent tiles. Land combat units that enter adjacent tile receive the ability, ''Spear of Fionn'' (+5 combat strength).'),
    ('LOC_FEATURE_GOBUSTAN_DESCRIPTION', 'Three tile natural wonder. Provides +1 [ICON_Production] Production and +3 [ICON_CULTURE] Culture.'),
    ('LOC_FEATURE_BARRIER_REEF_DESCRIPTION', 'Two tile natural wonder. Provides +3 [ICON_Food] Food and +2 [ICON_Science] Science. Provides major adjacency bonus to Campus district.'),
    ('LOC_FEATURE_HA_LONG_BAY_DESCRIPTION', 'Two tile natural wonder. Provides +3 [ICON_Food] Food, +1 [ICON_Production] Production, and +1 [ICON_Culture] Culture. +15 [ICON_Strength] Combat Strength when defending in this tile.'),
    ('LOC_FEATURE_IKKIL_DESCRIPTION', 'One tile impassable natural wonder. Provides Fresh Water. +50% [ICON_Production] Production when producing wonders and districts in adjacent tiles.'),
    ('LOC_FEATURE_LAKE_RETBA_DESCRIPTION', 'Two tile natural wonder. It appears as Lake and provides +1 [ICON_Production] Production, +2 [ICON_Gold] Gold, and +2 [ICON_Culture] Culture. Does not provide Fresh Water.'),
    ('LOC_FEATURE_LYSEFJORDEN_DESCRIPTION', 'Three tile impassable natural wonder. Provides +1 [ICON_Production] Production to adjacent tiles. Naval combat units that enter adjacent tile for the first time are granted their next promotion.'),
    ('LOC_FEATURE_MATTERHORN_DESCRIPTION', 'One tile impassable natural wonder. It appears as Mountain and provides +1 [ICON_Culture] Culture to adjacent tiles. Land combat units that enter adjacent tile gain +3 [ICON_Strength] Combat Strength and ignore Movement penalty in Hills.'),
    ('LOC_FEATURE_EVEREST_DESCRIPTION', 'Three tile impassable natural wonder. It appears as Mountain and provides +1 [ICON_Faith] Faith to adjacent tiles. Religious units that enter adjacent tile ignore Movement penalty in Hills.'),
    ('LOC_FEATURE_KILIMANJARO_XP2_DESCRIPTION', 'One tile impassable natural wonder. It appears as Volcano and provides +2 [ICON_Food] Food to adjacent tiles. On eruption it gives low yields and is most likely to damage improvements and buildings. Infrequently erupts, but is always active.'),
    ('LOC_FEATURE_RORAIMA_DESCRIPTION', 'Four tile impassable natural wonder. It appears as Mountain and provides +1 [ICON_Science] Science and +1 [ICON_Faith] Faith to adjacent tiles.'),
    ('LOC_FEATURE_VESUVIUS_DESCRIPTION', 'One tile impassable natural wonder. It appears as Volcano and provides +1 [ICON_Production] Production to adjacent tiles. On Eruption it gives high yields to adjacent tiles, but large [ICON_Citizen] Population loss. It is always active.'),
    ('LOC_FEATURE_PAITITI_DESCRIPTION', 'Three tile impassable natural wonder. Provides +3 [ICON_Gold] Gold and +2 [ICON_Culture] Culture to adjacent tiles. The city that owns at least one of the tiles receives +4 [ICON_Gold] Gold on its outgoing international [ICON_TradeRoute] Trade Routes.'),
    ('LOC_FEATURE_PAMUKKALE_DESCRIPTION', 'Two tile impassable natural wonder. Provides Fresh Water. The city that owns at least one of the tiles receives +1 [ICON_AMENITIES] Amenity, and extra +1 [ICON_AMENITIES] Amenity if adjacent to Entertainment Complex district. Provides major adjacency bonus to Theater Square, Campus, and Commercial Hub district, and standard adjacency bonus to Holy Site district.'),
    ('LOC_FEATURE_PANTANAL_DESCRIPTION', 'Four tile natural wonder. It appears as Marsh and provides +2 [ICON_Food] Food and +2 [ICON_Culture] Culture.'),
    ('LOC_FEATURE_PIOPIOTAHI_DESCRIPTION', 'Three tile impassable natural wonder. Provides +1 [ICON_Gold] Gold and +1 [ICON_Culture] Culture to adjacent tiles.'),
    ('LOC_FEATURE_WHITEDESERT_DESCRIPTION', 'Four tile natural wonder. Provides +1 [ICON_SCIENCE] Science, +1 [ICON_Culture] Culture, and +4 [ICON_GOLD] Gold.'),
    ('LOC_FEATURE_TORRES_DEL_PAINE_DESCRIPTION', 'Two tile impassable natural wonder. Doubles terrain yields of adjacent tiles.'),
    ('LOC_FEATURE_TSINGY_DESCRIPTION', 'One tile impassable natural wonder. Provides +1 [ICON_Science] Science and +1 [ICON_Culture] Culture to adjacent tiles.'),
    ('LOC_FEATURE_UBSUNUR_HOLLOW_DESCRIPTION', 'Four tile natural wonder. It appears as Marsh and provides +1 [ICON_Food] Food, +1 [ICON_Production] Production, and +2 [ICON_Faith] Faith.'),
    ('LOC_FEATURE_ULURU_DESCRIPTION', 'One tile impassable natural wonder. Provides +2 [ICON_Culture] Culture and +2 [ICON_Faith] Faith to adjacent tiles. Provides +4 appeal, instead of the usual +2 appeal to adjacent tiles.'),
    ('LOC_FEATURE_YOSEMITE_XP2_DESCRIPTION', 'Two tile impassable natural wonder. Provides +1 [ICON_Food] Food, +1 [ICON_Gold] Gold and +1 [ICON_Science] Science to adjacent tiles.'),
    ('LOC_FEATURE_ZHANGYE_DANXIA_DESCRIPTION', 'Three tile impassable natural wonder. It appears as Mountain. If you own at least one of the tiles, you receive 2 [ICON_GREATGENERAL] Great General points and 2 [ICON_GREATMERCHANT] Great Merchant points.');
